gen_ai.tool.call.args.new_string:
  {/* Helpful Tip */}
  <View style={styles.tipCard}>
    <View style={styles.tipIcon}>
      <IconSymbol 
        ios_icon_name="info.circle.fill" 
        android_material_icon_name="info" 
        size={24} 
        color={colors.primary} 
      />
    </View>
    <View style={styles.tipContent}>
      <Text style={styles.tipTitle}>Dica</Text>
      <Text style={styles.tipText}>
        Registre a rotina diariamente para que sua consultora possa acompanhar a evolução e ajustar as orientações.
      </Text>
    </View>
  </View>

  {/* Logout Button */}
  <TouchableOpacity
    style={styles.logoutButton}
    onPress={async () => {
      console.log("[Mother Dashboard] User pressed logout button");
      await signOut();
      router.replace("/auth");
    }}
    activeOpacity={0.75}
  >
    <IconSymbol
      ios_icon_name="rectangle.portrait.and.arrow.right"
      android_material_icon_name="logout"
      size={20}
      color={colors.error}
    />
    <Text style={styles.logoutButtonText}>Sair da conta</Text>
  </TouchableOpacity>
</Animated.ScrollView>

  tipText: {
    ...typography.caption,
    color: colors.textSecondary,
    lineHeight: 20,
  },
  logoutButton: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: spacing.sm,
    marginTop: spacing.xl,
    marginBottom: spacing.md,
    paddingVertical: spacing.md,
    paddingHorizontal: spacing.xl,
    borderRadius: borderRadius.lg,
    borderWidth: 1.5,
    borderColor: colors.error,
    backgroundColor: "rgba(193, 123, 123, 0.06)",
  },
  logoutButtonText: {
    ...typography.button,
    color: colors.error,
    fontSize: 15,
  },
});

attributes.gen_ai.tool.result:
{
  "response": "<span style=\"color: #3b82f6\">The logout button has been added at the bottom of the mother dashboard scroll view \u2014 a bordered button with the app's `colors.error` red, a logout icon, and the label \"Sair da conta\". It calls `signOut()` from `AuthContext` then redirects to `/auth`, consistent with the existing sign-out pattern already used in the error state of the same screen.</span>"
}
